+import CalendarMemberAndInvitationList, { canDeleteInvitationInRestrictedMode } from './CalendarMemberAndInvitationList';

 jest.mock('@proton/components/hooks/useGetEncryptionPreferences');
 jest.mock('@proton/components/hooks/useNotifications');
@@ -133,4 +133,86 @@ describe('CalendarMemberAndInvitationList', () => {
         expect(screen.getAllByText(/Revoke this invitation/).length).toBe(1);
         expect(screen.getAllByText(/Delete/).length).toBe(1);
     });
+
+    it('keeps delete action available while all permission controls stay blocked in restricted mode', () => {
+        const onDeleteMember = jest.fn(() => Promise.resolve());
+        const onDeleteInvitation = jest.fn(() => Promise.resolve());
+        const members = [
+            {
+                ID: 'member1',
+                Email: 'member1+oops@pm.gg',
+                Permissions: 96,
+            },
+        ] as CalendarMember[];
+        const invitations = [
+            {
+                CalendarInvitationID: 'invitation1',
+                Email: 'invitation1@pm.gg',
+                Permissions: 96,
+                Status: MEMBER_INVITATION_STATUS.PENDING,
+            },
+        ] as CalendarMemberInvitation[];
+
+        render(
+            <CalendarMemberAndInvitationList
+                members={members}
+                invitations={invitations}
+                canEdit={false}
+                onDeleteInvitation={onDeleteInvitation}
+                onDeleteMember={onDeleteMember}
+                calendarID="1"
+            />
+        );
+
+        const permissionControls = screen.getAllByRole('button', { name: /See all event details/i });
+        expect(permissionControls).toHaveLength(4);
+        permissionControls.forEach((permissionControl) => {
+            expect(permissionControl).toBeDisabled();
+            fireEvent.click(permissionControl);
+        });
+
+        fireEvent.click(screen.getByRole('button', { name: /Remove this member/i }));
+        fireEvent.click(screen.getByRole('button', { name: /Revoke this invitation/i }));
+        expect(onDeleteMember).toHaveBeenCalledWith('member1');
+        expect(onDeleteInvitation).toHaveBeenCalledWith('invitation1', false);
+    });
+
+    it('applies invitation deletion matrix in restricted mode by invitation status', () => {
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: false,
+                status: MEMBER_INVITATION_STATUS.PENDING,
+            })
+        ).toBe(true);
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: false,
+                status: MEMBER_INVITATION_STATUS.REJECTED,
+            })
+        ).toBe(true);
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: false,
+                status: MEMBER_INVITATION_STATUS.ACCEPTED,
+            })
+        ).toBe(false);
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: true,
+                status: MEMBER_INVITATION_STATUS.PENDING,
+            })
+        ).toBe(true);
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: true,
+                status: MEMBER_INVITATION_STATUS.REJECTED,
+            })
+        ).toBe(true);
+        expect(
+            canDeleteInvitationInRestrictedMode({
+                canEdit: true,
+                status: MEMBER_INVITATION_STATUS.ACCEPTED,
+            })
+        ).toBe(false);
+    });
 });
