@@ -0,0 +1,71 @@
+import { canRunPermissionUpdate, runPermissionUpdateIfAllowed } from './CalendarMemberRow';
+
+describe('canRunPermissionUpdate', () => {
+    it('enforces restricted permission guards before mutation callbacks', async () => {
+        expect(
+            canRunPermissionUpdate({
+                canEdit: false,
+                newPermissions: 96,
+                currentPermissions: 64,
+            })
+        ).toBe(false);
+        expect(
+            canRunPermissionUpdate({
+                canEdit: true,
+                newPermissions: 96,
+                currentPermissions: 96,
+            })
+        ).toBe(false);
+        expect(
+            canRunPermissionUpdate({
+                canEdit: true,
+                newPermissions: 112,
+                currentPermissions: 96,
+            })
+        ).toBe(false);
+        expect(
+            canRunPermissionUpdate({
+                canEdit: true,
+                newPermissions: 96,
+                currentPermissions: 64,
+            })
+        ).toBe(true);
+
+        const onPermissionsUpdate = jest.fn(() => Promise.resolve());
+        const withLoadingPermissionsUpdate = jest.fn(async (promise: Promise<void>) => promise);
+        const setPerms = jest.fn();
+
+        await runPermissionUpdateIfAllowed({
+            canEdit: false,
+            newPermissions: 96,
+            currentPermissions: 64,
+            onPermissionsUpdate,
+            withLoadingPermissionsUpdate,
+            setPerms,
+        });
+
+        await runPermissionUpdateIfAllowed({
+            canEdit: true,
+            newPermissions: 96,
+            currentPermissions: 64,
+            onPermissionsUpdate,
+            withLoadingPermissionsUpdate,
+            setPerms,
+        });
+
+        await runPermissionUpdateIfAllowed({
+            canEdit: true,
+            newPermissions: 96,
+            currentPermissions: 96,
+            onPermissionsUpdate,
+            withLoadingPermissionsUpdate,
+            setPerms,
+        });
+
+        expect(onPermissionsUpdate).toHaveBeenCalledTimes(1);
+        expect(onPermissionsUpdate).toHaveBeenCalledWith(96);
+        expect(withLoadingPermissionsUpdate).toHaveBeenCalledTimes(1);
+        expect(setPerms).toHaveBeenCalledWith(96);
+    });
+
+});
