@@ -0,0 +1,28 @@
+import { resolveRestrictedCalendarAccess } from './CalendarSubpage';
+
+describe('resolveRestrictedCalendarAccess', () => {
+    it('applies restricted access policy matrix for canEdit and canShare', () => {
+        const cases = [
+            {
+                input: { hasNonDelinquentScope: false, calendarPermissions: 96, isOwnedCalendar: true },
+                expected: { canEdit: false, canShare: false },
+            },
+            {
+                input: { hasNonDelinquentScope: true, calendarPermissions: 0, isOwnedCalendar: true },
+                expected: { canEdit: false, canShare: false },
+            },
+            {
+                input: { hasNonDelinquentScope: true, calendarPermissions: 96, isOwnedCalendar: false },
+                expected: { canEdit: true, canShare: false },
+            },
+            {
+                input: { hasNonDelinquentScope: true, calendarPermissions: 96, isOwnedCalendar: true },
+                expected: { canEdit: true, canShare: true },
+            },
+        ] as const;
+
+        cases.forEach(({ input, expected }) => {
+            expect(resolveRestrictedCalendarAccess(input)).toEqual(expected);
+        });
+    });
+});
